var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"등대라고?","JPN":"灯台？","ENG":"Lighthouse?","TWN":"燈塔？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇다. 등대다.","JPN":"そう、灯台だ。","ENG":"Yes, the Lighthouse.","TWN":"沒錯，燈塔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"등대라면 바닷가에 있는 그거잖아?","JPN":"灯台って海近に建ってるあれだよね？","ENG":"A lighthouse, as in the tower near the shore?","TWN":"你是說海邊的那個燈塔嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"수영복이라도 가져와야 하나?","JPN":"水着でも持って行ったほうがいいかな？","ENG":"Do I have to bring a swimsuit?","TWN":"那要帶泳衣嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음, 아마 의뢰인께서 말씀하신 등대는 그게 아닐 겁니다.","JPN":"ふむ、おそらく依頼主さんが仰っている灯台は、その灯台ではないでしょう。","ENG":"Hmm, I don’t think she means that.","TWN":"咳咳，委託人說的燈塔應該不是那個燈塔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리국에서 발굴한 고출력 좌표 신호기의 별명이 등대거든요.","JPN":"管理局が発掘した高出力座標信号機の別名が灯台なんです。","ENG":"The Lighthouse is what we call the high-powered coordinate signaler the Administration found.","TWN":"管理局挖掘到的高能座標信號器，也暱稱為燈塔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"항법 장치에 기준 좌표를 제공해서 이면세계에서도 길을 잃지 않게 해 주는 장치죠.","JPN":"航法装置に基準座標を提供して、\\n裏世界で道に迷わないようにする装置の事です。","ENG":"It’s a device that provides standard coordination to the navigation system, so that you won’t get lost in the Counterside.","TWN":"它可以提供導航系統法線座標，叫人不在異界中迷路。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"훌륭하다.","JPN":"見事だ。","ENG":"Excellent.","TWN":"厲害。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"가문을 일으키기 위해선 무력뿐 아니라 지성도 필요한 법.","JPN":"一族を再び興すためには、武力だけではなく知性も必要。","ENG":"To revive a family, you need not only force, but intelligence as well.","TWN":"要興旺家族之人不能光靠蠻力，還必須要有聰明智慧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그대와 같은 지적인 남자가 우리 가문의 일원이 된다면 좋을 텐데.","JPN":"そなたのような知的な男が我が一族の一員になってくれればいいのだが。","ENG":"It would be nice to have an intelligent man like you in my family.","TWN":"我希望像你這般有智慧的男人，能夠成為我們家族的一員。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어……","JPN":"……え？","ENG":"Huh?","TWN":"呃……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"혹시 이거 그거야? 프로포즈? 이렇게 갑자기……?","JPN":"もしかしてこれってあれ？　プロポーズ？　こんな急に……？","ENG":"Are you proposing to him? Just like that? Out of nowhere?","TWN":"難道這就是那個嗎？求婚？這麼突然……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그럴 리가 있겠습니까.","JPN":"ハハ、そんな訳ないでしょう。","ENG":"Haha, she is not.","TWN":"哈哈，怎麼可能。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 오해를 부르는 화법은 조금 교정할 필요가 있겠네요.","JPN":"ですが、誤解を招く話し方は少し直す必要がありそうですね。","ENG":"But it is true that the way you talk could cause some misunderstandings.","TWN":"不過你的說話方式確實容易引起誤會，需要調整一下。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말이라는 게 뉘앙스도 중요한 거라서 자칫 잘못하면 파국을 부를 수도 있거든요.","JPN":"言葉というのはニュアンスが大事ですよ。\\n下手したら言葉によって破滅を招きますからね。","ENG":"You see, nuance is very important. It could cause disaster if you were to make a mistake.","TWN":"說話的時候語調很重要，一點點的差異都可能導致聽的人有誤會。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"과연……. 그렇군.","JPN":"ふむ……なるほど。","ENG":"Oh... I see.","TWN":"原來……如此。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"나의 부모님들도 말이 가져온 재앙으로 인해 파멸을 맞았지.","JPN":"私の両親も言葉がもたらした災いによって破滅を迎えた。","ENG":"My parents also sealed their fates with their tongues.","TWN":"我的父母親也是因為話語引發的災難而滅亡的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"또다시 이방인에게 좋은 가르침을 얻었다.","JPN":"異邦人からまた良い教えを得た。","ENG":"Another good lesson from an outsider.","TWN":"再次從外邦人身上學到好的教導呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"감사를 표한다.","JPN":"礼を言う。","ENG":"I am much obliged.","TWN":"謝謝。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"주, 중간에 뭔가 엄청난 이야기가 섞여 있었던 것 같은데……?","JPN":"な、なんかさらっとすごいこと言ってた気がするんだけど……？","ENG":"D-didn’t you just mention something shocking in between?","TWN":"剛剛是在講什麼人生大道理嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이거 참, 인생에 굴곡이 많은 의뢰인이신 것 같네요.","JPN":"依頼主さんは紆余曲折があった人生を歩んで来られたようですね。","ENG":"Oh my, I see you had a difficult life.","TWN":"也沒有啦，只是我們的委託人似乎遇到不少難過的事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무튼, 등대의 원본은 모 국 정보부가 추진한 비공식 작전 중에 유실된 걸로 알려져 있어요.","JPN":"話がそれましたが、灯台の元となったものは某国の情報部が推進していた\\n非公式作戦中に失ったと言われています。","ENG":"Anyway, the original Lighthouse went missing during a secret operation run by an intelligence agency from another country.","TWN":"總之據我所知，燈塔是在某個國家的情報部所推動的非官方作戰中，不慎遺失的東西。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리국이 회수하려고 몇 차례 시도한 적 있지만, 모두 실패했습니다.","JPN":"管理局が何度も回収をしようとしましたが、すべて失敗しました。","ENG":"The Administration tried to retrieve it a few times, but failed.","TWN":"管理局雖然多次嘗試要將它收回，卻都以失敗作收。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어째서? 그냥 가져오면 되는 거 아냐?","JPN":"どうして？　持ってくるだけじゃないの？","ENG":"Why? Couldn’t they just bring it back?","TWN":"怎麼會？不就直接拿回來就好了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"등대의 신호는 길 잃은 자들에게 등불이 되어 주죠.","JPN":"灯台の信号は、道に迷った者にとっての灯りになります。","ENG":"The Lighthouse sends out signals to people who are lost.","TWN":"燈塔的信號成為迷路之人的引路燈。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그건, 침식체들에게도 마찬가지거든요.","JPN":"でもそれは侵食体にとっても同じなんです。","ENG":"But C.O.s can see the signal as well.","TWN":"但對於侵蝕體而言亦是如此。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"등대가 유실된 지역 근처는 그 불빛에 모여든 침식체들이 엄청나게 많아요.","JPN":"灯台を失くした地域の近くには、その灯りに集まった侵食体たちが多くいます。","ENG":"So the area where the Lighthouse went missing is now crowded with C.O.s.","TWN":"燈塔所在的位置周圍，總是有許多被那道光吸引而來的侵蝕體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"거기다가 차원 폭풍까지 불어오는 곳이라 어지간한 용병들도 접근하지 않는 위험지대죠.","JPN":"それに、次元の暴風まで吹き荒れる場所なので、\\n腕の立つ傭兵すら近づかない危険地帯です。","ENG":"There are dimensional storms as well. Even seasoned mercenaries won’t go there.","TWN":"再加上甚至會刮起次元風暴，因此一般的傭兵是無法靠近的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 쉽지 않은 의뢰가 되겠어요, 미나 양.","JPN":"これは簡単には終わらない依頼になりそうですね、ミナさん。","ENG":"I don’t think it will be an easy task, Mina.","TWN":"米娜，這次的委託可能不容易喔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 상관없어. 침식체가 많다는 건 부수입이 될 이터니움도 많다는 뜻이니까.","JPN":"構わないよ。侵食体がたくさんいるってことは、\\n副収入になるエタニウムもいっぱいあるってことだから。","ENG":"I don’t care. More C.O.s means more Eternium.","TWN":"我無所謂，侵蝕體多就表示永恆之金也多，我還可以趁機撈點油水。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고…… 이번 일은 의뢰인님 가족과 관계된 일인거지?","JPN":"それに……今回の依頼はあなたの家族にも関係があることだよね？","ENG":"And this job... It’s got something to do with your family, right?","TWN":"再說……這次的委託事關委託人的家族不是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……그렇게 볼 수도 있다.","JPN":"……そうとも言える。","ENG":"... You could say that.","TWN":"……是可以這麼說。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러면 더 힘을 내야지.","JPN":"だったら頑張らないと。","ENG":"Then we should try even harder.","TWN":"那就更應該認真達成囉！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말 위험해지면 사장님이 준 장비도 있고 말이야.","JPN":"本当に危険な状況になったら、社長からもらった装備を使えばいいしね。","ENG":"I also have gear from the Boss, just in case something happens.","TWN":"萬一真的有危險，我還有老闆送我的裝備！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"긍정적이라서 좋군요.","JPN":"ポジティブでいいですね。","ENG":"I’m glad you’re so positive.","TWN":"非常好！這麼正面積極。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러면 몰려든 침식체들을 뚫느라 시간이 좀 걸릴 것 같습니다만…… 괜찮으신가요?","JPN":"集まった侵食体を突破するのに時間がかかりそうですが……大丈夫ですか？","ENG":"Well, taking out the C.O.s might take some time... Will you be okay with this?","TWN":"不過要突破侵蝕體的重圍，應該會需要花一些時間……你沒問題吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"나는 문제 없다.","JPN":"私は問題ない。","ENG":"I am fine with it.","TWN":"沒問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그대들이 싸우는 모습을 조금 더 봐 두고 싶기도 하고.","JPN":"そなたたちが戦う姿をもう少し見ておきたい。","ENG":"Also I would like to see how you fight.","TWN":"我也想多看幾眼你們戰鬥的姿態。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"좋습니다. 그러면 가볼까요?","JPN":"わかりました。それでは、行ってみましょうか？","ENG":"Good, shall we go now?","TWN":"很好，那就出發吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};